SpringContextUtil——获取spring中的bean对象@Componentpublic class SpringContextUtil implements ApplicationContextAware &#123;    //Spring应用上下文环境    private static ApplicationContext applicationContext;    /**     * 实现ApplicationContextAware接口的回调方法，设置上下文环境     *     * @param applicationContext     * @throws BeansException     */    @Override    public void setApplicationContext(ApplicationContext applicationContext) throws BeansException &#123;        System.out.println(&quot;执行ApplicationContext对象注入!&quot;);        SpringContextUtil.applicationContext = applicationContext;    &#125;    public static ApplicationContext getApplicationContext() &#123;        return applicationContext;    &#125;    /**     * 获取对象     *     * @return Object 一个以类型     * @throws BeansException     */    public static &lt;T&gt; T getBean(Class&lt;T&gt; requiredType) throws BeansException &#123;        return applicationContext.getBean(requiredType);    &#125;    /**     * 获取对象     *     * @param name     * @return Object 一个以所给名字注册的bean的实例     * @throws BeansException     */    public static Object getBean(String name) throws BeansException &#123;        return applicationContext.getBean(name);    &#125;    /**     * 获取类型为requiredType的对象     * 如果bean不能被类型转换，相应的异常将会被抛出（BeanNotOfRequiredTypeException）     *     * @param name        bean注册名     * @param requireType 返回对象类型     * @return Object 返回requiredType类型对象     * @throws BeansException     */    public static &lt;T&gt; T getBean(String name, Class&lt;T&gt; requireType) throws BeansException &#123;        return applicationContext.getBean(name, requireType);    &#125;    /**     * 如果BeanFactory包含一个与所给名称匹配的bean定义，则返回true     *     * @param name     * @return boolean     */    public static boolean containsBean(String name) &#123;        return applicationContext.containsBean(name);    &#125;    /**     * 判断以给定名字注册的bean定义是一个singleton还是一个prototype。     * 如果与给定名字相应的bean定义没有被找到，将会抛出一个异常（NoSuchBeanDefinitionException）     *     * @param name     * @return