实现一个简单 IoC 容器定义需要实例化对象的类的全限定类名以及类之间依赖关系的描述。
核心代码public class BeanFactory &#123;    private final static Map&lt;String, Object&gt; map = new HashMap&lt;&gt;();    static &#123;        InputStream resource = Resource.getResourceAsStream(&quot;beans.xml&quot;);        SAXReader saxReader = new SAXReader();        try &#123;            Document document = saxReader.read(resource);            Element rootElement = document.getRootElement();            List&lt;Element&gt; beanList = rootElement.selectNodes(&quot;//bean&quot;);            for (Element element : beanList) &#123;                String id = element.attributeValue(&quot;id&quot;);                String clazz = element.attributeValue(&quot;class&quot;);                Object object = newInstance(clazz);                map.put(id, object);            &#125;            List&lt;Element&gt; properties = rootElement.selectNodes(&quot;//property&quot;);            for (Element property : properties) &#123;                String name = property.attributeValue(&quot;name&quot;);                String ref = property.attributeValue(&quot;ref&quot;);                //父元素                Element parent = property.getParent();                String id = parent.attributeValue(&quot;id&quot;);                Object parentBean = getBean(id);                Method[] methods = parentBean.getClass().getDeclaredMethods();                for (Method method : methods) &#123;                    if ((&quot;set&quot; + name).equalsIgnoreCase(method.getName())) &#123;                        //给父元素的成员变量赋值                        Object bean = getBean(ref);                        method.invoke(parentBean, bean);                        break;                    &#125;                &#125;                map.put(id, parentBean);            &#125;        &#125; catch (DocumentException | ClassNotFoundException | NoSuchMethodException | InvocationTargetException |                 InstantiationException | IllegalAccessException e) &#123;            throw new RuntimeException(e);        &#125;    &#125;    private static Object newInstance(String clazz) throws ClassNotFoundException, NoSuchMethodException, InstantiationException, IllegalAccessException, InvocationTargetException &#123;        Class&lt;?&gt; aClass = Class.forName(clazz);        Constructor&lt;?&gt; constructor = aClass.getDeclaredConstructor();        return constructor.newInstance();    &#125;    public static &lt;T&gt; T getBean(String id) &#123;        return (T) map.get(id);    &#125;&#125;

