通过动态代理，将横切代码块与业务代码分离。
JDK 动态代理方式public class TransactionProxyFactory&lt;T&gt; implements InvocationHandler &#123;    private final T t;    public TransactionProxyFactory(T t) &#123;        this.t = t;    &#125;    public &lt;E extends T&gt; T getTarget() &#123;        return (E) Proxy.newProxyInstance(t.getClass().getClassLoader(), t.getClass().getInterfaces(), this);    &#125;        @Override    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable &#123;        try &#123;            TransactionManager.beginTransaction();            Object result = method.invoke(t, args);            TransactionManager.commit();            return result;        &#125; catch (Exception e) &#123;            e.printStackTrace();            TransactionManager.rollback();            throw e;        &#125;    &#125;&#125;


Cglib 动态代理方式public class TransactionCglibProxyFactory&lt;T&gt; implements MethodInterceptor &#123;    private final Class&lt;? extends T&gt; clazz;    public TransactionCglibProxyFactory(Class&lt;? extends T&gt; clazz) &#123;        this.clazz = clazz;    &#125;    public &lt;E extends T&gt; T getTarget() &#123;        Enhancer enhancer = new Enhancer();        enhancer.setSuperclass(clazz);        enhancer.setCallback(this);        return (E) enhancer.create();    &#125;    @Override    public Object intercept(Object obj, Method method, Object[] args, MethodProxy proxy) throws Throwable &#123;        try &#123;            TransactionManager.beginTransaction();            Object result = proxy.invokeSuper(obj, args);            TransactionManager.commit();            return result;        &#125; catch (Exception e) &#123;            e.printStackTrace();            TransactionManager.rollback();            throw e;        &#125;    &#125;&#125;

